import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { FiPlus, FiTrendingUp, FiBell, FiShoppingBag, FiTrash2 } from 'react-icons/fi';

const API_URL = 'http://localhost:5000/api';

function Dashboard() {
  const [products, setProducts] = useState([]);
  const [stats, setStats] = useState({
    total_products: 0,
    buy_now: 0,
    wait: 0,
    buy_soon: 0
  });
  const [showAddModal, setShowAddModal] = useState(false);
  const [newProductUrl, setNewProductUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [deletingId, setDeletingId] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProducts();
    fetchStats();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await axios.get(`${API_URL}/products`, {
        withCredentials: true
      });
      setProducts(response.data || []);
    } catch (error) {
      console.error('Error fetching products:', error);
      toast.error('Failed to load products');
      setProducts([]);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_URL}/dashboard/stats`, {
        withCredentials: true
      });
      setStats(response.data || {
        total_products: 0,
        buy_now: 0,
        wait: 0,
        buy_soon: 0
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const addProduct = async () => {
    if (!newProductUrl.trim()) {
      toast.error('Please enter a product URL');
      return;
    }

    setLoading(true);
    try {
      await axios.post(`${API_URL}/products`, 
        { url: newProductUrl },
        { withCredentials: true }
      );
      toast.success('Product added successfully!');
      setShowAddModal(false);
      setNewProductUrl('');
      await fetchProducts();
      await fetchStats();
    } catch (error) {
      console.error('Error adding product:', error);
      toast.error(error.response?.data?.error || 'Failed to add product');
    } finally {
      setLoading(false);
    }
  };

  const deleteProduct = async (productId, event) => {
    event.stopPropagation(); // Prevent navigating to product detail
    
    if (!window.confirm('Are you sure you want to remove this product?')) {
      return;
    }
    
    setDeletingId(productId);
    try {
      await axios.delete(`${API_URL}/products/${productId}`, {
        withCredentials: true
      });
      toast.success('Product removed successfully');
      await fetchProducts();
      await fetchStats();
    } catch (error) {
      console.error('Error deleting product:', error);
      toast.error('Failed to remove product');
    } finally {
      setDeletingId(null);
    }
  };

  const getDecisionColor = (decision) => {
    switch(decision) {
      case 'BUY_NOW': return 'decision-buy-now';
      case 'BUY_SOON': return 'decision-buy-soon';
      default: return 'decision-wait';
    }
  };

  const getDecisionText = (decision) => {
    switch(decision) {
      case 'BUY_NOW': return '🟢 BUY NOW';
      case 'BUY_SOON': return '🟡 BUY SOON';
      default: return '🔴 WAIT';
    }
  };

  return (
    <div className="dashboard">
      {/* Stats Cards */}
      <div className="stats-container">
        <div className="stat-card">
          <FiShoppingBag size={32} color="#48bb78" />
          <div className="stat-value">{stats.total_products || 0}</div>
          <div className="stat-label">Total Products</div>
        </div>
        <div className="stat-card">
          <FiTrendingUp size={32} color="#48bb78" />
          <div className="stat-value">{stats.buy_now || 0}</div>
          <div className="stat-label">Buy Now</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{stats.buy_soon || 0}</div>
          <div className="stat-label">Buy Soon</div>
        </div>
        <div className="stat-card">
          <FiBell size={32} color="#f56565" />
          <div className="stat-value">{stats.wait || 0}</div>
          <div className="stat-label">Wait</div>
        </div>
      </div>

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Your Products</h2>
        <button onClick={() => setShowAddModal(true)} className="add-product-btn">
          <FiPlus /> Add Product
        </button>
      </div>

      {/* Products Grid */}
      {products.length === 0 ? (
        <div className="empty-state">
          <FiShoppingBag size={64} color="#a0aec0" />
          <h3>No products yet</h3>
          <p>Click the "Add Product" button to start tracking prices!</p>
          <button onClick={() => setShowAddModal(true)} style={{ marginTop: '20px' }}>
            <FiPlus /> Add Your First Product
          </button>
        </div>
      ) : (
        <div className="dashboard-grid">
          {products.map(product => (
            <div 
              key={product.id} 
              className="product-card"
              onClick={() => navigate(`/product/${product.id}`)}
            >
              <div className="product-card-header">
                <h3>{product.name || 'Product'}</h3>
                <button 
                  className="delete-btn"
                  onClick={(e) => deleteProduct(product.id, e)}
                  disabled={deletingId === product.id}
                >
                  <FiTrash2 />
                </button>
              </div>
              <div className="price">${(product.current_price || 0).toFixed(2)}</div>
              <div className={`decision-badge ${getDecisionColor(product.decision)}`}>
                {getDecisionText(product.decision)}
              </div>
              <div className="confidence-score">
                Confidence: {product.confidence || 0}%
              </div>
              {product.original_price && product.original_price > product.current_price && (
                <div className="savings">
                  Save ${(product.original_price - product.current_price).toFixed(2)}
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Add Product Modal */}
      {showAddModal && (
        <div className="modal-overlay" onClick={() => setShowAddModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h3>Add New Product</h3>
            <p style={{ marginBottom: '15px', fontSize: '0.9rem', color: 'var(--text-secondary)' }}>
              Enter any product URL (Amazon, Flipkart, etc.)
            </p>
            <input
              type="text"
              placeholder="https://www.amazon.com/product-name/dp/..."
              value={newProductUrl}
              onChange={(e) => setNewProductUrl(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && addProduct()}
              autoFocus
            />
            <div className="modal-buttons">
              <button onClick={addProduct} disabled={loading} className="submit-btn">
                {loading ? 'Adding...' : 'Add Product'}
              </button>
              <button onClick={() => setShowAddModal(false)} className="cancel-btn">
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Styles */}
      <style jsx>{`
        .stats-container {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
          margin-bottom: 30px;
        }

        .stat-card {
          background: var(--bg-secondary);
          border-radius: 12px;
          padding: 20px;
          text-align: center;
          box-shadow: var(--card-shadow);
          transition: transform 0.2s ease;
        }

        .stat-card:hover {
          transform: translateY(-2px);
        }

        .stat-value {
          font-size: 2rem;
          font-weight: bold;
          color: #48bb78;
          margin: 10px 0;
        }

        .stat-label {
          color: var(--text-secondary);
          font-size: 0.9rem;
        }

        .dashboard-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
          gap: 20px;
          margin-top: 20px;
        }

        .product-card {
          background: var(--bg-secondary);
          border-radius: 12px;
          padding: 20px;
          box-shadow: var(--card-shadow);
          transition: all 0.2s ease;
          cursor: pointer;
          border: 1px solid var(--border-color);
          position: relative;
        }

        .product-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 8px 16px rgba(0, 0, 0, 0.15);
        }

        .product-card-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 10px;
        }

        .product-card-header h3 {
          font-size: 1rem;
          margin: 0;
          flex: 1;
          color: var(--text-primary);
          overflow: hidden;
          text-overflow: ellipsis;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
        }

        .delete-btn {
          background: transparent;
          color: #f56565;
          padding: 5px;
          margin: -5px;
          font-size: 1rem;
          width: auto;
          opacity: 0.6;
          transition: opacity 0.2s ease;
        }

        .delete-btn:hover {
          opacity: 1;
          background: transparent;
        }

        .delete-btn:disabled {
          opacity: 0.3;
          cursor: not-allowed;
        }

        .price {
          font-size: 1.8rem;
          font-weight: bold;
          color: #48bb78;
          margin: 10px 0;
        }

        .decision-badge {
          display: inline-block;
          padding: 4px 12px;
          border-radius: 20px;
          font-size: 0.85rem;
          font-weight: 600;
          margin: 10px 0;
        }

        .decision-buy-now {
          background-color: #48bb78;
          color: white;
        }

        .decision-buy-soon {
          background-color: #ecc94b;
          color: #1a202c;
        }

        .decision-wait {
          background-color: #f56565;
          color: white;
        }

        .confidence-score {
          font-size: 0.85rem;
          color: var(--text-secondary);
          margin-top: 5px;
        }

        .savings {
          font-size: 0.8rem;
          color: #48bb78;
          margin-top: 8px;
          font-weight: 500;
        }

        .empty-state {
          text-align: center;
          padding: 60px 20px;
          background: var(--bg-secondary);
          border-radius: 12px;
          color: var(--text-secondary);
        }

        .empty-state h3 {
          margin: 20px 0 10px;
          color: var(--text-primary);
        }

        .add-product-btn {
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 1000;
          animation: fadeIn 0.2s ease;
        }

        .modal-content {
          background: var(--bg-secondary);
          padding: 30px;
          border-radius: 12px;
          width: 90%;
          max-width: 500px;
          animation: slideUp 0.2s ease;
        }

        .modal-content h3 {
          margin-bottom: 10px;
          color: var(--text-primary);
        }

        .modal-content input {
          width: 100%;
          padding: 12px;
          border: 1px solid var(--border-color);
          border-radius: 8px;
          background: var(--bg-primary);
          color: var(--text-primary);
          font-size: 1rem;
          margin: 15px 0;
        }

        .modal-content input:focus {
          outline: none;
          border-color: #48bb78;
        }

        .modal-buttons {
          display: flex;
          gap: 10px;
          justify-content: flex-end;
        }

        .submit-btn {
          background: #48bb78;
        }

        .cancel-btn {
          background: #a0aec0;
        }

        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }

        @keyframes slideUp {
          from {
            transform: translateY(20px);
            opacity: 0;
          }
          to {
            transform: translateY(0);
            opacity: 1;
          }
        }

        @media (max-width: 768px) {
          .dashboard-grid {
            grid-template-columns: 1fr;
          }
          
          .stats-container {
            grid-template-columns: repeat(2, 1fr);
          }
        }
      `}</style>
    </div>
  );
}

export default Dashboard;
